class Solution {
    public String robotWithString(String s) {
        StringBuilder t = new StringBuilder();
        StringBuilder p = new StringBuilder();
        while (!s.isEmpty() || t.length() > 0) {
            while (!s.isEmpty() && (t.length() == 0 || s.charAt(0) <= t.charAt(t.length() - 1))) {
                t.append(s.charAt(0));
                s = s.substring(1);
            }
            if (!t.isEmpty()) {
                p.append(t.charAt(t.length() - 1));
                t.deleteCharAt(t.length() - 1);
            }
        }
        return p.toString();
    }
}
